      type: String,
      default: 'OMR'
    }
  },
  category: {
    type: String,
    trim: true
  },
  type: {
    type: String,
    enum: ['full-time', 'part-time', 'contract', 'freelance'],
    default: 'full-time'
  },
  postedDate: {
    type: Date,
    default: Date.now
  },
  expiryDate: Date,
  applicationLink: String,
  source: {
    type: String,
    default: 'wazfnynow.com'
  },
  externalId: String
}, {
  timestamps: true
});

// Application Schema
const applicationSchema = new mongoose.Schema({
