    API_KEY = "your_api_key_here"  # Replace with your actual API key
    devices = get_smart_home_devices(API_KEY)

    if devices:
        print(f"Found {len(devices)} devices:")
        for device in devices:
            print(f"- {device.get('name')} (${device.get('price', 'N/A')})")
